fn _random_gaussian(mean: f64, stddev: f64) f64 {
    const _gu1 = _rng().float(f64);
    const _gu2 = _rng().float(f64);
    const _gz = @sqrt(-2.0 * @log(_gu1)) * @cos(2.0 * std.math.pi * _gu2);
    return mean + stddev * _gz;
